import"./app-yIULqX0W.js";window.Auth&&window.Auth.isLoggedIn()&&(window.location.href="/pages/dashboard.html");const s=document.getElementById("register-form");s&&s.addEventListener("submit",async a=>{a.preventDefault();const e=document.getElementById("submit-btn"),t=document.getElementById("reg-error");t.classList.remove("visible"),e.disabled=!0,e.innerHTML='<span class="spinner"></span> Creating account…';try{await window.apiFetch("/auth/register",{method:"POST",body:JSON.stringify({full_name:document.getElementById("full_name").value,email:document.getElementById("email").value,password:document.getElementById("password").value})}),window.toast("Account created","success"),setTimeout(()=>window.location.href="/pages/login.html",800)}catch(n){window.toast(n.message,"error"),t.textContent=n.message,t.classList.add("visible")}finally{e&&(e.disabled=!1,e.innerHTML="Create free account")}});
